import 'package:flutter/material.dart';import 'package:url_launcher/url_launcher.dart';import 'package:url_launcher/url_launcher_string.dart';import '../../../../../Core/Utils/Widget/custom_scaffold_messenger.dart';import '../../../../../Core/Utils/extensions.dart';import '../../../../../Core/Utils/text_style.dart';import '../../../../Home/Data/model/book_model.dart';class ButtonBuilder extends StatelessWidget {  final BookModel item;  const ButtonBuilder({super.key, required this.item});  @override  Widget build(BuildContext context) {    return Padding(      padding: const EdgeInsets.only(top: 37),      child:      Row(        mainAxisAlignment: MainAxisAlignment.center,        children: [          InkWell(            onTap: () async {              showSnackBar(context,'Added in Card');            },            child: Container(              height: 50,              width: MediaQuery.of(context).size.width * .40,              decoration: const BoxDecoration(                  color: Color(0xffFFFFFF),                  borderRadius:                      BorderRadius.horizontal(left: Radius.circular(15))),              child: Center(                child: Text(                  isFree(item.saleInfo!),                  style: Styles.textStyle20.copyWith(                      fontWeight: FontWeight.bold, color: Colors.black),                ),              ),            ),          ),          InkWell(            onTap: () async {              final Uri urlLink = Uri.parse(item.volumeInfo!.previewLink!);              if (await launchUrl(urlLink)) {                await launchUrl(                  urlLink,                );              }            },            child: Container(              height: 50,              width: MediaQuery.of(context).size.width * .40,              decoration: const BoxDecoration(                  color: Color(0xffEF8262),                  borderRadius:                      BorderRadius.horizontal(right: Radius.circular(15))),              child: const Center(                child: Text(                  "preview",                  style: Styles.textStyle16,                ),              ),            ),          )        ],      ),    );  }}